CREATE EXTENSION IF NOT EXISTS pgcrypto;

DO $$ BEGIN CREATE TYPE user_role AS ENUM ('admin','sales','project_manager','support','finance','read_only'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE opportunity_status AS ENUM ('new','qualified','proposal','negotiation','won','lost'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE project_status AS ENUM ('planned','active','on_hold','completed','cancelled'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE ticket_status AS ENUM ('open','in_progress','waiting_customer','resolved','closed'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE TYPE invoice_status AS ENUM ('draft','sent','part_paid','paid','overdue','void'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

CREATE TABLE IF NOT EXISTS users (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text, email text UNIQUE NOT NULL, password_hash text NOT NULL, role user_role NOT NULL DEFAULT 'read_only', created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS companies (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, domain text, industry text, phone text, address text, status text DEFAULT 'prospect', created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS contacts (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), company_id uuid REFERENCES companies(id) ON DELETE CASCADE, first_name text NOT NULL, last_name text NOT NULL, email text, phone text, title text, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS clients (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), company_id uuid REFERENCES companies(id) ON DELETE CASCADE, name text NOT NULL, email text, status text DEFAULT 'active', created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS leads (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), company_id uuid REFERENCES companies(id) ON DELETE SET NULL, contact_id uuid REFERENCES contacts(id) ON DELETE SET NULL, source text, status text DEFAULT 'new', estimated_value_minor integer DEFAULT 0, notes text, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS opportunities (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), company_id uuid REFERENCES companies(id) ON DELETE CASCADE, lead_id uuid REFERENCES leads(id) ON DELETE SET NULL, name text NOT NULL, stage opportunity_status DEFAULT 'new', deal_value_minor integer DEFAULT 0, probability integer DEFAULT 10, expected_close_date date, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS quotes (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), opportunity_id uuid REFERENCES opportunities(id) ON DELETE CASCADE, quote_number text UNIQUE NOT NULL, status text DEFAULT 'draft', subtotal_minor integer DEFAULT 0, tax_minor integer DEFAULT 0, total_minor integer DEFAULT 0, valid_until date, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS quote_lines (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), quote_id uuid REFERENCES quotes(id) ON DELETE CASCADE, description text NOT NULL, quantity integer DEFAULT 1, unit_price_minor integer DEFAULT 0, tax_rate numeric(5,2) DEFAULT 20, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS projects (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), company_id uuid REFERENCES companies(id) ON DELETE CASCADE, opportunity_id uuid UNIQUE REFERENCES opportunities(id) ON DELETE SET NULL, client_id uuid REFERENCES clients(id) ON DELETE SET NULL, name text NOT NULL, status project_status DEFAULT 'planned', priority int DEFAULT 3, budget_minor integer DEFAULT 0, estimated_cost_minor integer DEFAULT 0, actual_cost_minor integer DEFAULT 0, progress int DEFAULT 0, due_date date, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS tasks (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), project_id uuid REFERENCES projects(id) ON DELETE CASCADE, title text NOT NULL, status text DEFAULT 'todo', assignee text, due_date date, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS milestones (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), project_id uuid REFERENCES projects(id) ON DELETE CASCADE, name text NOT NULL, due_date date, completed_at timestamptz, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS tickets (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), company_id uuid REFERENCES companies(id) ON DELETE CASCADE, project_id uuid REFERENCES projects(id) ON DELETE SET NULL, assigned_user_id uuid REFERENCES users(id) ON DELETE SET NULL, subject text NOT NULL, priority text DEFAULT 'medium', status ticket_status DEFAULT 'open', internal_notes text, sla_due_at timestamptz, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS ticket_comments (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), ticket_id uuid REFERENCES tickets(id) ON DELETE CASCADE, user_id uuid REFERENCES users(id) ON DELETE SET NULL, body text NOT NULL, customer_visible boolean DEFAULT false, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS invoices (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), company_id uuid REFERENCES companies(id) ON DELETE CASCADE, project_id uuid REFERENCES projects(id) ON DELETE SET NULL, client_id uuid REFERENCES clients(id) ON DELETE SET NULL, invoice_number text UNIQUE NOT NULL, status invoice_status DEFAULT 'draft', subtotal_minor integer DEFAULT 0, tax_minor integer DEFAULT 0, total_minor integer DEFAULT 0, amount numeric(12,2) DEFAULT 0, due_date date, paid_at timestamptz, created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS invoice_lines (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), invoice_id uuid REFERENCES invoices(id) ON DELETE CASCADE, description text NOT NULL, quantity integer DEFAULT 1, unit_price_minor integer DEFAULT 0, tax_rate numeric(5,2) DEFAULT 20, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS payments (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), invoice_id uuid REFERENCES invoices(id) ON DELETE CASCADE, amount_minor integer NOT NULL, paid_at timestamptz DEFAULT now(), method text, reference text, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS activities (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), company_id uuid REFERENCES companies(id) ON DELETE CASCADE, opportunity_id uuid REFERENCES opportunities(id) ON DELETE CASCADE, project_id uuid REFERENCES projects(id) ON DELETE CASCADE, ticket_id uuid REFERENCES tickets(id) ON DELETE CASCADE, invoice_id uuid REFERENCES invoices(id) ON DELETE CASCADE, type text NOT NULL, body text NOT NULL, created_by uuid REFERENCES users(id) ON DELETE SET NULL, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS reports (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), kind text NOT NULL, title text NOT NULL, content jsonb NOT NULL, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS ai_memory (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), memory_type text NOT NULL, subject text NOT NULL, content text NOT NULL, metadata jsonb DEFAULT '{}', created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS decisions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), decision text NOT NULL, rationale text, outcome text, created_at timestamptz DEFAULT now());
CREATE TABLE IF NOT EXISTS monitoring_checks (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), check_type text NOT NULL, target text NOT NULL, status text NOT NULL, details jsonb DEFAULT '{}', checked_at timestamptz DEFAULT now());
CREATE INDEX IF NOT EXISTS idx_projects_status ON projects(status); CREATE INDEX IF NOT EXISTS idx_invoices_status ON invoices(status); CREATE INDEX IF NOT EXISTS idx_opportunities_stage ON opportunities(stage); CREATE INDEX IF NOT EXISTS idx_tickets_status ON tickets(status); CREATE INDEX IF NOT EXISTS idx_activity_links ON activities(company_id, opportunity_id, project_id, ticket_id, invoice_id);
